import React from 'react';
import { NavLink } from 'react-router-dom';
import styles from './Header.module.css';

export default function Header() {
  return (
    <header className={styles.header}>
      <div className={styles.brand}>Hackathon Platform</div>
      <nav className={styles.nav}>
        <NavLink to="/" end className={({isActive}) => isActive ? styles.active : ''}>Головна</NavLink>
        <NavLink to="/competitions" className={({isActive}) => isActive ? styles.active : ''}>Змагання</NavLink>
        <NavLink to="/projects" className={({isActive}) => isActive ? styles.active : ''}>Проєкти</NavLink>
        <NavLink to="/rating" className={({isActive}) => isActive ? styles.active : ''}>Рейтинг</NavLink>
      </nav>
    </header>
  );
}
